function solve(landStartTime, landDuration, waterStartTime, waterDuration) {
    let minTime = Infinity;

    for (let i = 0; i < landStartTime.length; i++) {
        const landStart = landStartTime[i];
        const landEnd = landStart + landDuration[i];
        for (let j = 0; j < waterStartTime.length; j++) {
            const waterStart = waterStartTime[j];
            const waterEnd = waterStart + waterDuration[j];

            // Case 1: land first, then water
            const startWater = Math.max(landEnd, waterStart);
            const totalTime1 = startWater + waterDuration[j];
            if (totalTime1 < minTime) {
                minTime = totalTime1;
            }

            // Case 2: water first, then land
            const startLand = Math.max(waterEnd, landStart);
            const totalTime2 = startLand + landDuration[i];
            if (totalTime2 < minTime) {
                minTime = totalTime2;
            }
        }
    }

    return minTime;
}
